import{_ as t,o,c as n,ag as i}from"./chunks/framework.BKDXG6j6.js";const h=JSON.parse('{"title":"General Android Interview Questions","description":"","frontmatter":{},"headers":[],"relativePath":"interview/android-questions.md","filePath":"interview/android-questions.md","lastUpdated":null}'),a={name:"interview/android-questions.md"};function r(s,e,c,d,l,u){return o(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="general-android-interview-questions" tabindex="-1">General Android Interview Questions <a class="header-anchor" href="#general-android-interview-questions" aria-label="Permalink to &quot;General Android Interview Questions&quot;">​</a></h1><p>These questions test the baseline foundational knowledge expected of intermediate to senior Android developers.</p><h3 id="_1-context-and-memory" tabindex="-1">1. Context and Memory <a class="header-anchor" href="#_1-context-and-memory" aria-label="Permalink to &quot;1. Context and Memory&quot;">​</a></h3><p><strong>Q: What is a <code>Context</code>? What is the difference between Application Context and Activity Context?</strong></p><ul><li><strong>Answer:</strong> <code>Context</code> provides access to application-specific resources and classes, as well as up-calls for application-level operations (launching activities, broadcasting, receiving intents).</li><li>You use <strong>Activity Context</strong> when dealing with UI operations (e.g., creating a View, inflating layouts, showing Dialogs) because it contains the theme and style of the current screen.</li><li>You use <strong>Application Context</strong> when a singleton or background service needs a context (e.g., initiating a Room database instance), because it is tied to the lifecycle of the entire app process, thus preventing memory leaks.</li></ul><p><strong>Q: How do you identify and fix a Memory Leak in Android?</strong></p><ul><li><strong>Answer:</strong> A memory leak occurs when the Garbage Collector cannot free an object holding onto memory because there is an active reference pointing to it (often an Activity or View).</li><li><strong>Tools:</strong> Use LeakCanary during development. Use Android Studio Memory Profiler to take a Heap Dump and trace the offending GC Root.</li><li><strong>Fix:</strong> Clear references in <code>onDestroy()</code> using nullification. Avoid placing <code>Context</code> in companion objects. Make sure inner classes containing callbacks are static, or utilize coroutine scopes correctly (<code>viewModelScope</code>) so long-running async tasks are automatically cancelled before the host Activity dies.</li></ul><h3 id="_2-lifecycles-and-state" tabindex="-1">2. Lifecycles and state <a class="header-anchor" href="#_2-lifecycles-and-state" aria-label="Permalink to &quot;2. Lifecycles and state&quot;">​</a></h3><p><strong>Q: If an Activity is destroyed and recreated on screen rotation, how can you save UI state?</strong></p><ul><li><strong>Answer:</strong><ol><li><code>ViewModel</code>: Perfect for retaining heavy, complex domain objects during simple configuration changes.</li><li><code>SavedStateHandle</code>: Used inside the ViewModel to serialize simple parameters (String, Int, IDs) into an OS bundle. It survives both configuration changes AND System-Initiated Process Death (when the OS kills apps in the background to save battery/RAM).</li><li><code>onSaveInstanceState()</code>: Legacy method if not using ViewModel.</li></ol></li></ul><h3 id="_3-concurrency-and-background-tasks" tabindex="-1">3. Concurrency and Background Tasks <a class="header-anchor" href="#_3-concurrency-and-background-tasks" aria-label="Permalink to &quot;3. Concurrency and Background Tasks&quot;">​</a></h3><p><strong>Q: Explain the difference between <code>WorkManager</code>, <code>Services</code>, and <code>Coroutines</code>.</strong></p><ul><li><strong>Answer:</strong><ul><li><strong>Coroutines:</strong> Best for executing immediate asynchronous work tied to a screen or user session perfectly synchronized with lifecycles. If the app kills the screen/process, the background work is terminated.</li><li><strong>Foreground Service:</strong> Best for tasks where the user is actively aware the app is doing work in the background (playing music, tracking a workout via GPS) and expects it not to be killed aggressively. Must show an ongoing notification.</li><li><strong>WorkManager:</strong> Best for deferrable, guaranteed background work. E.g., uploading analytics logs or syncing the database offline. WorkManager guarantees execution regardless of app reboots or sudden kills, while also respecting battery conditions (e.g., &quot;only run on unmetered Wi-Fi while charging&quot;).</li></ul></li></ul><h3 id="_4-application-architecture" tabindex="-1">4. Application Architecture <a class="header-anchor" href="#_4-application-architecture" aria-label="Permalink to &quot;4. Application Architecture&quot;">​</a></h3><p><strong>Q: Explain how clean Unidirectional Data Flow (UDF) works in Compose and MVVM.</strong></p><ul><li><strong>Answer:</strong> UDF requires State to flow strictly downwards, and Events to flow strictly upwards. <ul><li>The UI Screen (Composable/Fragment) triggers an intent/event: e.g., &quot;Login Button Clicked&quot;.</li><li>The UI passes the event <em>up</em> to the ViewModel.</li><li>The ViewModel processes the login via the repository on a background thread.</li><li>The ViewModel mutates the single source of truth (<code>StateFlow&lt;UiState&gt;</code>).</li><li>The UI Screen observes this StateFlow and instantly reacts to it <em>downward</em>, re-rendering itself to show the &quot;Loading spinner&quot; or &quot;Success screen&quot;.</li></ul></li></ul><h3 id="_5-advanced-misc" tabindex="-1">5. Advanced / Misc <a class="header-anchor" href="#_5-advanced-misc" aria-label="Permalink to &quot;5. Advanced / Misc&quot;">​</a></h3><p><strong>Q: What is a custom <code>View</code> and how do you create one?</strong></p><ul><li><strong>Answer:</strong> When standard widgets (<code>TextView</code>, <code>Button</code>) don’t fit your needs, you can extend the <code>View</code> class. You override <code>onMeasure()</code> to dictate exactly what width and height the view demands, and <code>onDraw(canvas)</code> to manually paint bitmaps, paths, circles, and text using <code>Paint</code> objects onto the screen frame.</li></ul>',19)])])}const p=t(a,[["render",r]]);export{h as __pageData,p as default};
